/// <reference path="./plugin.d.ts" />
/// <reference path="./system.d.ts" />
/// <reference path="./app.d.ts" />

/**
 * AnimeKai Skip Data Plugin
 *
 * Fetches intro/outro skip timestamps from enc-dec.app (AnimeKai database)
 * and applies them to the built-in Seanime video player.
 *
 * Two modes (toggle via tray):
 *  - "default_fallback"  Use Seanime native skip data; fall back to AnimeKai
 *                        only when the player reports no data.
 *  - "animekai_only"     Always override with AnimeKai data.
 */

// ─── Main ──────────────────────────────────────────────────────────────────

function init() {
    $ui.register((ctx) => {

        const MODE_STORAGE_KEY = "skip-data-manager.mode"
        const DEFAULT_MODE = "default_fallback"

        // ─── Helpers ───────────────────────────────────────────────────────────────

        function findEpisodeData(animeData: any, episodeNumber: number): any {
            if (!animeData || typeof animeData.episodes !== "object") return null
            for (const groupKey of Object.keys(animeData.episodes)) {
                const group = animeData.episodes[groupKey]
                if (group && group[String(episodeNumber)]) {
                    return group[String(episodeNumber)]
                }
            }
            return null
        }

        function buildSkipData(episodeData: any): any | null {
            const source = episodeData?.sources?.sub
            if (!source?.skip) return null

            const intro: number[] | undefined = source.skip.intro
            const outro: number[] | undefined = source.skip.outro

            const skipData: any = { op: null, ed: null }

            if (Array.isArray(intro) && intro.length === 2 && intro[1] > intro[0] && intro[1] > 0) {
                skipData.op = { interval: { startTime: intro[0], endTime: intro[1] } }
            }
            if (Array.isArray(outro) && outro.length === 2 && outro[1] > outro[0] && outro[1] > 0) {
                skipData.ed = { interval: { startTime: outro[0], endTime: outro[1] } }
            }

            return (skipData.op || skipData.ed) ? skipData : null
        }

        function hasSkipData(data: any): boolean {
            if (!data) return false
            return !!(data.op?.interval || data.ed?.interval)
        }

        // ── Persistent mode state ───────────────────────────────────────────
        const savedMode = $storage.get<string>(MODE_STORAGE_KEY) ?? DEFAULT_MODE
        const mode = ctx.state<string>(savedMode)

        function setMode(newMode: string) {
            mode.set(newMode)
            $storage.set(MODE_STORAGE_KEY, newMode)
        }

        // ── In-session data cache keyed by AniList ID ───────────────────────
        const dataCache: Record<string, any> = {}

        async function fetchAnimeKaiData(anilistId: number): Promise<any> {
            const key = String(anilistId)
            if (dataCache[key] !== undefined) return dataCache[key]

            try {
                const res = await ctx.fetch(
                    `https://enc-dec.app/db/kai/find?anilist_id=${anilistId}`
                )
                const json = await res.json()
                const entry = Array.isArray(json) ? (json[0] ?? null) : (json ?? null)
                dataCache[key] = entry
                return entry
            } catch (err) {
                console.error("[skip-data-manager] fetch error:", err)
                dataCache[key] = null
                return null
            }
        }

        async function applyAnimeKaiSkipData(anilistId: number, episodeNumber: number): Promise<void> {
            const animeData = await fetchAnimeKaiData(anilistId)
            if (!animeData) {
                console.log("[skip-data-manager] No data for AniList ID:", anilistId)
                return
            }

            const episodeData = findEpisodeData(animeData, episodeNumber)
            if (!episodeData) {
                console.log("[skip-data-manager] No data for episode", episodeNumber)
                return
            }

            const skipData = buildSkipData(episodeData)
            if (!skipData) {
                console.log("[skip-data-manager] Empty intervals for episode", episodeNumber)
                return
            }

            ctx.videoCore.setSkipData(skipData)
            ctx.videoCore.showMessage("AnimeKai skip data applied", 2500)
            console.log("[skip-data-manager] Applied:", JSON.stringify(skipData))
        }

        // ── Playback event handlers ─────────────────────────────────────────

        // animekai_only — apply immediately when the video loads
        ctx.videoCore.addEventListener("video-loaded", async () => {
            if (mode.get() !== "animekai_only") return

            const media = ctx.videoCore.getCurrentMedia()
            const info  = ctx.videoCore.getCurrentPlaybackInfo()
            const anilistId     = media?.id
            const episodeNumber = info?.episode?.episodeNumber

            if (!anilistId || !episodeNumber) return
            await applyAnimeKaiSkipData(anilistId, episodeNumber)
        })

        // default_fallback — wait for video-can-play so native AniSkip data
        // has had time to be set, then only inject if nothing is present.
        ctx.videoCore.addEventListener("video-can-play", async () => {
            if (mode.get() !== "default_fallback") return

            const media = ctx.videoCore.getCurrentMedia()
            const info  = ctx.videoCore.getCurrentPlaybackInfo()
            const anilistId     = media?.id
            const episodeNumber = info?.episode?.episodeNumber

            if (!anilistId || !episodeNumber) return

            try {
                const existing = await ctx.videoCore.getSkipData()
                if (hasSkipData(existing)) {
                    console.log("[skip-data-manager] Native skip data present — skipping")
                    return
                }
            } catch {
                return
            }

            await applyAnimeKaiSkipData(anilistId, episodeNumber)
        })

        // ── Tray UI ─────────────────────────────────────────────────────────
        const tray = ctx.newTray({
            tooltipText: "Skip Data Manager",
            iconUrl: "https://enc-dec.app/favicon.ico",
            withContent: true,
        })

        ctx.registerEventHandler("set-mode-default", () => {
            setMode("default_fallback")
            ctx.toast.success("Mode: Default + AnimeKai fallback")
        })

        ctx.registerEventHandler("set-mode-animekai", () => {
            setMode("animekai_only")
            ctx.toast.success("Mode: AnimeKai only")
        })

        tray.render(() => {
            const isDefault = mode.get() === "default_fallback"
            return tray.stack({
                items: [
                    tray.text("Skip Data Manager"),
                    tray.text(
                        isDefault
                            ? "Mode: Default + AnimeKai fallback"
                            : "Mode: AnimeKai"
                    ),
                    tray.flex([
                        tray.button("Default + AnimeKai Fallback", { onClick: "set-mode-default" }),
                        tray.button("AnimeKai",      { onClick: "set-mode-animekai" }),
                    ], { gap: 2 }),
                ],
            })
        })
    })
}
